    fun socialGmailGoalPreflightJson(context: Context): JSONObject {
        val appContext = context.applicationContext
        val packageManager = appContext.packageManager
        val tikTok = packageStatusJson(packageManager, "TikTok", TIKTOK_PACKAGES)
        val instagram = packageStatusJson(packageManager, "Instagram", listOf(INSTAGRAM_PACKAGE))
        val gmail = packageStatusJson(packageManager, "Gmail", listOf(GMAIL_PACKAGE))
        val preferredModel = preferredLocalModelJson(appContext)
        val deviceIdentity = deviceIdentityJson()
        val physicalPhoneDetected = !isLikelyEmulatorDevice()
        val blockers = JSONArray()
        if (!physicalPhoneDetected) {
            blockers.put("Current Android target appears to be an emulator or virtual device; the requested end-to-end goal requires a physical phone")
        }
        if (!tikTok.optBoolean("installed")) {
            blockers.put("TikTok is not installed or visible to Hermes (${TIKTOK_PACKAGES.joinToString()})")
        }
        if (!instagram.optBoolean("installed")) {
            blockers.put("Instagram is not installed or visible to Hermes ($INSTAGRAM_PACKAGE)")
        }
        if (!gmail.optBoolean("installed")) {
            blockers.put("Gmail is not installed or visible to Hermes ($GMAIL_PACKAGE)")
        }
        if (!HermesAccessibilityController.isServiceEnabled(appContext)) {
            blockers.put("Hermes accessibility service is not enabled; UI snapshots, typing, scrolling, and send/post taps need it")
        } else if (!HermesAccessibilityController.isServiceConnected()) {
            blockers.put("Hermes accessibility service is enabled but not connected yet; open Hermes or toggle the service before UI actions")
        }
        if (!preferredModel.optBoolean("ready")) {
            blockers.put("No preferred local model file is ready; use the local model import button or download a model first")
        }
        return JSONObject()
            .put("success", true)
            .put("action", "social_gmail_goal_preflight")
            .put("objective", "TikTok video comment, TikTok hello DM, Instagram hello DM, Gmail latest-email summary, and Gmail self-email to adybag14@gmail.com using local Gemma/Qwen on the physical phone")
            .put("physical_phone_required", true)
            .put("physical_phone_detected", physicalPhoneDetected)
            .put("android_device_identity", deviceIdentity)
            .put("tiktok", tikTok)
            .put("instagram", instagram)
            .put("gmail", gmail)
            .put("accessibility_service_enabled", HermesAccessibilityController.isServiceEnabled(appContext))
            .put("accessibility_connected", HermesAccessibilityController.isServiceConnected())
            .put("foreground_package_name", HermesAccessibilityController.currentForegroundPackageName())
            .put("preferred_local_model", preferredModel)
            .put("local_model_import_button_supported", true)
            .put("local_model_import_entry", "Settings > Hugging Face local model downloads > Import model from phone files")
            .put("local_model_import_uses_android_open_document", true)
            .put("ready_for_social_ui_actions", physicalPhoneDetected && tikTok.optBoolean("installed") && instagram.optBoolean("installed") && HermesAccessibilityController.isServiceConnected())
            .put("ready_for_gmail_draft", gmail.optBoolean("installed"))
            .put("ready_for_gmail_latest_email_summary", physicalPhoneDetected && gmail.optBoolean("installed") && HermesAccessibilityController.isServiceConnected())
            .put("ready_for_local_model_run", preferredModel.optBoolean("ready"))
            .put("ready_for_full_goal", blockers.length() == 0)
            .put("blocking_items", blockers)
            .put(
                "gmail_latest_email_summary_strategy",
                JSONObject()
                    .put("method", "Open Gmail, use android_ui_tool snapshots to inspect the inbox/latest email UI, then summarize visible sender/subject/body text.")
                    .put("direct_mailbox_read_supported", false)
                    .put("requires_gmail_installed", true)
                    .put("requires_accessibility_snapshot", true)
                    .put("ready", physicalPhoneDetected && gmail.optBoolean("installed") && HermesAccessibilityController.isServiceConnected()),
            )
            .put("external_send_requires_visible_confirmation", true)
            .put(
                "external_send_safety_checks",
                JSONArray()
                    .put("Before posting the TikTok comment, confirm the current visible video/comment composer is the intended target.")
                    .put("Before each DM send, confirm the current visible TikTok or Instagram conversation recipient is the intended target.")
                    .put("Before tapping Gmail Send, confirm the composer is addressed to adybag14@gmail.com with the intended subject/body."),
            )
            .put(
                "suggested_phone_sequence",
                JSONArray()
                    .put("Run this preflight after the physical phone is attached.")
                    .put("Do not treat emulator-only app/model results as completion for this goal.")
                    .put("If local_model_import_button_supported is true but preferred_local_model.ready is false, use the import button to import a Gemma LiteRT-LM or Qwen GGUF model and mark it preferred.")
                    .put("For the latest Gmail summary, open the latest message in Gmail and summarize only text verified in the current UI snapshot.")
                    .put("Use android_ui_tool snapshots before every external send/post tap.")
                    .put("Use android_device_diagnostics_tool action=social_gmail_goal_preflight again after permissions, installs, or model changes."),
            )
            .put(
                "cards",
                JSONArray()
                    .put(card("Phone Goal Preflight", if (blockers.length() == 0) "All required package/model/accessibility checks are ready." else "${blockers.length()} blocker(s) remain before the full phone run."))
                    .put(card("Send Safety", "External posts, DMs, and email sends require a fresh UI snapshot confirming target and content immediately before tapping send.")),
            )
    }

    private fun deviceIdentityJson(): JSONObject {
        return JSONObject()
            .put("manufacturer", Build.MANUFACTURER.orEmpty())
            .put("brand", Build.BRAND.orEmpty())
            .put("model", Build.MODEL.orEmpty())
            .put("device", Build.DEVICE.orEmpty())
            .put("product", Build.PRODUCT.orEmpty())
            .put("hardware", Build.HARDWARE.orEmpty())
            .put("fingerprint", Build.FINGERPRINT.orEmpty())
            .put("soc_profile", socProfileJson())
            .put("likely_emulator", isLikelyEmulatorDevice())
    }

    private fun agentCapabilityMatrixRows(
        context: Context,
        diagnostics: JSONObject,
        signalStatus: JSONObject,
        radioStatus: JSONObject,
        preferredModel: JSONObject,
        hindsightStatus: JSONObject,
        automationStatus: JSONObject,
        modelRouting: JSONObject,
        socProfile: JSONObject,
        availableSensors: JSONArray,
    ): JSONArray {
        val wifiPermission = diagnostics.optJSONObject("wifi_scan_permission_status") ?: JSONObject()
        val bluetoothPermission = diagnostics.optJSONObject("bluetooth_scan_permission_status") ?: JSONObject()
        val motionSensors = jsonStringList(signalStatus.optJSONArray("motion_sensor_analysis_supported"))
        val packageManager = context.packageManager
        val wifiSupported = packageManager.hasSystemFeature(PackageManager.FEATURE_WIFI)
        val bluetoothSupported = packageManager.hasSystemFeature(PackageManager.FEATURE_BLUETOOTH)
        val screenshotSupported = Build.VERSION.SDK_INT >= Build.VERSION_CODES.R
        return JSONArray()
            .put(
                capabilityRow(
                    category = "local_model",
                    label = "On-device inference",
                    ready = preferredModel.optBoolean("ready"),
                    valueLabel = preferredModel.optString("title").ifBlank { "model import needed" },
                    detail = listOf(
                        preferredModel.optString("runtime_flavor").ifBlank { "unknown runtime" },
                        preferredModel.optString("record_status").ifBlank { "no preferred record" },
                    ).joinToString(" | "),
                    recommendation = "Use a preferred Gemma 4 LiteRT-LM or Qwen GGUF model before treating the phone as fully autonomous offline.",
                    fraction = if (preferredModel.optBoolean("ready")) 1f else 0.35f,
                ),
            )
            .put(
                capabilityRow(
                    category = "multimodal",
                    label = "Vision and image attachments",
                    ready = modelRouting.optBoolean("vision_capable", false) && screenshotSupported,
                    valueLabel = if (modelRouting.optBoolean("vision_capable", false)) "vision-ready" else "text-first",
                    detail = "Chat image attachments and accessibility screenshots are available for Gemma/VLM workflows when the active model supports images.",
                    recommendation = "Use android_ui_tool visual_snapshot or chat image attachments when semantic UI text is insufficient.",
                    fraction = if (modelRouting.optBoolean("vision_capable", false)) 0.9f else 0.45f,
                ),
            )
            .put(
                capabilityRow(
                    category = "soc_backend",
                    label = "SOC and LiteRT backend policy",
                    ready = true,
                    valueLabel = socProfile.optString("litert_lm_acceleration_label").ifBlank { socProfile.optString("soc_family_label").ifBlank { "Android SOC" } },
                    detail = listOf(
                        socProfile.optString("soc_family_label").ifBlank { "unknown SOC" },
                        socProfile.optString("gpu_family_label").ifBlank { "unknown GPU" },
                        socProfile.optString("primary_abi").ifBlank { "unknown ABI" },
                    ).joinToString(" | "),
                    recommendation = socProfile.optString("litert_lm_backend_strategy").ifBlank { "Prefer SOC-neutral GPU probing with CPU fallback; do not assume Snapdragon/Adreno only." },
                    fraction = 0.95f,
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi",
                    label = "Wi-Fi analyzer",
                    ready = wifiSupported && wifiPermission.optBoolean("can_read_scan_results", false),
                    valueLabel = if (wifiSupported) {
                        if (wifiPermission.optBoolean("can_read_scan_results", false)) "scan-ready" else "permission needed"
                    } else {
                        "no Wi-Fi feature"
                    },
                    detail = "Supports AP details, channel ratings, security/width/standard summaries, signal history, and exportable rows.",
                    recommendation = "Call wifi_scan, wifi_ap_details, or wifi_export for nearby signal/channel decisions.",
                    fraction = if (wifiSupported && wifiPermission.optBoolean("can_read_scan_results", false)) 1f else if (wifiSupported) 0.55f else 0.1f,
                ),
            )
            .put(
                capabilityRow(
                    category = "bluetooth",
                    label = "Bluetooth scanner",
                    ready = bluetoothSupported && bluetoothPermission.optBoolean("can_scan_nearby_devices", false),
                    valueLabel = if (bluetoothSupported) {
                        if (bluetoothPermission.optBoolean("can_scan_nearby_devices", false)) "scan-ready" else "permission needed"
                    } else {
                        "no Bluetooth feature"
                    },
                    detail = "Supports paired/BLE rows, RSSI proximity, service UUID labels, manufacturer names, and metadata cards.",
                    recommendation = "Call bluetooth_scan when nearby device identity, proximity, or BLE advertisement context matters.",
                    fraction = if (bluetoothSupported && bluetoothPermission.optBoolean("can_scan_nearby_devices", false)) 1f else if (bluetoothSupported) 0.55f else 0.1f,
                ),
            )
            .put(
                capabilityRow(
                    category = "radio",
                    label = "AM/FM and broad RF",
                    ready = radioStatus.optBoolean("am_fm_public_android_scan_supported", false),
                    valueLabel = if (radioStatus.optBoolean("requires_external_sdr_for_broad_rf", true)) "external SDR needed" else "built-in scan available",
                    detail = "Android public APIs expose Wi-Fi/Bluetooth/audio/sensors, but not a general AM/FM/microwave scan feed on normal phones.",
                    recommendation = "Use radio_signal_status for honest capability cards and route broad RF work to vendor APIs or external SDR hardware.",
                    fraction = if (radioStatus.optBoolean("am_fm_public_android_scan_supported", false)) 0.8f else 0.25f,
                ),
            )
            .put(
                capabilityRow(
                    category = "sensors",
                    label = "Motion and environmental sensors",
                    ready = motionSensors.isNotEmpty(),
                    valueLabel = "${motionSensors.size} motion type(s)",
                    detail = "Available sensors: ${jsonStringList(availableSensors).take(8).joinToString(", ").ifBlank { "none reported" }}",
                    recommendation = "Call sensor_snapshot or start_sensor_watcher for accelerometer, gyroscope, magnetic, ambient, and workflow-trigger context.",
                    fraction = (motionSensors.size / 5f).coerceIn(0.1f, 1f),
                ),
            )
            .put(
                capabilityRow(
                    category = "ui_control",
                    label = "UI perception and control",
                    ready = HermesAccessibilityController.isServiceConnected(),
                    valueLabel = if (HermesAccessibilityController.isServiceConnected()) "accessibility connected" else "enable accessibility",
                    detail = "Accessibility snapshots, screenshot hashes, OpenGUI-style VLM actions, and guarded UI actions are available when the service is enabled.",
                    recommendation = "Call android_ui_tool status/sense/visual_snapshot before sensitive UI actions or external sends.",
                    fraction = if (HermesAccessibilityController.isServiceConnected()) 1f else if (HermesAccessibilityController.isServiceEnabled(context)) 0.65f else 0.35f,
                ),
            )
            .put(
                capabilityRow(
                    category = "automation",
                    label = "Autonomous heartbeat and dispatch",
                    ready = automationStatus.optBoolean("standby_heartbeat_supported", false),
                    valueLabel = if (automationStatus.optBoolean("standby_heartbeat_supported", false)) "heartbeat-ready" else "not configured",
                    detail = "${automationStatus.optInt("enabled_automation_count", 0)} enabled automation(s), ${automationStatus.optInt("recent_run_count", 0)} recent run(s).",
                    recommendation = "Use android_automation_tool operator_standby_status/operator_heartbeat for Kai-style autonomous status and remote dispatch.",
                    fraction = if (automationStatus.optBoolean("standby_heartbeat_supported", false)) 0.9f else 0.4f,
                ),
            )
            .put(
                capabilityRow(
                    category = "memory",
                    label = "Persistent hindsight memory",
                    ready = true,
                    valueLabel = "${hindsightStatus.optInt("memory_count", 0)} memories",
                    detail = "${hindsightStatus.optInt("reinforced_memory_count", 0)} reinforced, ${hindsightStatus.optInt("promoted_memory_count", 0)} promoted for prompt context.",
                    recommendation = "Use hindsight_memory_tool retain/recall/relevant_context/reflect/promoted_context around complex work.",
                    fraction = ((hindsightStatus.optInt("promoted_memory_count", 0) + 1) / 5f).coerceIn(0.25f, 1f),
                ),
            )
    }

    fun agentSelfCheckReportJson(context: Context): JSONObject {
        val appContext = context.applicationContext
        val wifiReport = wifiAnalyzerReportJson(appContext, JSONObject().put("refresh", false))
        val bluetoothReport = bluetoothAnalyzerReportJson(appContext, JSONObject().put("refresh", false))
        val sensorReport = sensorAnalyzerReportJson(appContext, JSONObject().put("include_snapshot", false))
        val radioReport = radioSignalStatusJson(appContext)
        val signalReport = signalAwarenessReportJson(appContext)
        val rfReport = rfCoexistenceReportJson(appContext)
        val backendRiskReport = gpuBackendRiskReportJson(appContext)
        val acceleratorReport = acceleratorPreflightReportJson(appContext)
        val mediatekReport = mediatekReadinessReportJson(appContext)
        val backendAdvisorReport = nonAdrenoBackendAdvisorReportJson(appContext)
        val inferenceReport = localInferenceCompatibilityReportJson(appContext)
        val environmentReport = agentEnvironmentReportJson(appContext)
        val automationStatus = environmentReport.optJSONObject("automation_standby_status") ?: JSONObject()
        val toolSandboxRows = environmentReport.optJSONArray("agent_tool_sandbox_matrix") ?: JSONArray()
        val kaiOperationsRows = environmentReport.optJSONArray("kai_operations_matrix") ?: JSONArray()
        val workflowRows = environmentReport.optJSONArray("workflow_readiness_matrix") ?: JSONArray()
        val cardManifestSources = agentCardManifestSources(
            wifiReport = wifiReport,
            bluetoothReport = bluetoothReport,
            sensorReport = sensorReport,
            radioReport = radioReport,
            backendRiskReport = backendRiskReport,
            acceleratorReport = acceleratorReport,
            mediatekReport = mediatekReport,
            backendAdvisorReport = backendAdvisorReport,
            signalReport = signalReport,
            environmentReport = environmentReport,
        )
        val cardManifestRows = agentCardManifestRows(cardManifestSources)
        val selfCheckRows = agentSelfCheckMatrixRows(
            wifiReport = wifiReport,
            bluetoothReport = bluetoothReport,
            sensorReport = sensorReport,
            radioReport = radioReport,
            rfReport = rfReport,
            backendRiskReport = backendRiskReport,
            mediatekReport = mediatekReport,
            inferenceReport = inferenceReport,
            automationStatus = automationStatus,
            toolSandboxRows = toolSandboxRows,
            kaiOperationsRows = kaiOperationsRows,
            workflowRows = workflowRows,
            cardManifestRows = cardManifestRows,
        )
        val routeRows = agentSelfCheckRouteRows(automationStatus)
        return JSONObject()
            .put("success", true)
            .put("action", "agent_self_check_report")
            .put("report_scope", "Kai-style passive Hermes self-check for heartbeat readiness, wireless/radio/sensor observability, MediaTek/non-Adreno backend guardrails, expandable cards, and next diagnostic routes.")
            .put(
                "source_report_actions",
                JSONArray()
                    .put("agent_environment_report")
                    .put("wifi_analyzer_report")
                    .put("bluetooth_analyzer_report")
                    .put("sensor_analyzer_report")
                    .put("radio_signal_status")
                    .put("rf_coexistence_report")
                    .put("mediatek_readiness_report")
                    .put("gpu_backend_risk_report")
                    .put("accelerator_preflight_report")
                    .put("non_adreno_backend_advisor_report")
                    .put("local_inference_compatibility_report")
                    .put("agent_card_manifest_report"),
            )
            .put("automation_standby_status", automationStatus)
            .put("agent_environment_summary", observationSummaryJson(environmentReport, "agent_environment_report"))
            .put("wifi_observation_summary", observationSummaryJson(wifiReport, "wifi_analyzer_report"))
            .put("bluetooth_observation_summary", observationSummaryJson(bluetoothReport, "bluetooth_analyzer_report"))
            .put("sensor_observation_summary", observationSummaryJson(sensorReport, "sensor_analyzer_report"))
            .put("radio_observation_summary", observationSummaryJson(radioReport, "radio_signal_status"))
            .put("rf_coexistence_summary", observationSummaryJson(rfReport, "rf_coexistence_report"))
            .put("mediatek_readiness_summary", observationSummaryJson(mediatekReport, "mediatek_readiness_report"))
            .put("backend_risk_summary", observationSummaryJson(backendRiskReport, "gpu_backend_risk_report"))
            .put("accelerator_preflight_summary", observationSummaryJson(acceleratorReport, "accelerator_preflight_report"))
            .put("local_inference_summary", observationSummaryJson(inferenceReport, "local_inference_compatibility_report"))
            .put("agent_self_check_matrix", selfCheckRows)
            .put("agent_self_check_routes", routeRows)
            .put("agent_card_manifest", cardManifestRows)
            .put("agent_self_check_count", selfCheckRows.length())
            .put("ready_agent_self_check_count", countReadyRows(selfCheckRows))
            .put("agent_self_check_route_count", routeRows.length())
            .put("agent_card_manifest_count", cardManifestRows.length())
            .put(
                "self_check_directives",
                JSONArray()
                    .put("Run this passive self-check before long-running Android automation, local inference, Wi-Fi/Bluetooth/radio analysis, or MediaTek compatibility claims.")
                    .put("Treat heartbeat rows as status surfacing; they do not imply unrestricted background AI execution.")
                    .put("Use route rows to open the exact evidence card before changing settings, requesting active scans, or promising GPU acceleration.")
                    .put("Prefer passive analyzer reports first; request active Wi-Fi, Bluetooth, motion, or radio bridge samples only when current live evidence is needed."),
            )
            .put(
                "cards",
                JSONArray()
                    .put(
                        graphCard(
                            title = "Agent Self-Check",
                            body = "${selfCheckRows.length()} passive self-check row(s) covering heartbeat, signals, sensors, radio, backend risk, MediaTek readiness, local inference, and card coverage.",
                            graphType = "agent_self_check_matrix",
                            rows = selfCheckRows,
                        ),
                    )
                    .put(
                        graphCard(
                            title = "Self-Check Routes",
                            body = "${routeRows.length()} route row(s) for opening the right follow-up diagnostic card.",
                            graphType = "agent_self_check_routes",
                            rows = routeRows,
                        ),
                    )
                    .put(
                        graphCard(
                            title = "Agent Card Manifest",
                            body = "${cardManifestRows.length()} source card row(s) mapping graph types to source actions and refresh policies.",
                            graphType = "agent_card_manifest",
                            rows = cardManifestRows,
                        ),
                    ),
            )
    }

    private fun agentSignalWorkflowHandoffRows(
        signalEvidenceReport: JSONObject,
        priorityReport: JSONObject,
        wifiReport: JSONObject,
        bluetoothReport: JSONObject,
        sensorReport: JSONObject,
        radioStatusReport: JSONObject,
        radioAdvisorReport: JSONObject,
        mediatekReport: JSONObject,
        acceleratorReport: JSONObject,
        backendAdvisorReport: JSONObject,
        mcpRegistryReport: JSONObject,
        upgradeReport: JSONObject,
    ): JSONArray {
        val wifiGraphCount = wifiReport.optInt("wifi_channel_graph_count", wifiReport.optJSONArray("wifi_channel_graph")?.length() ?: 0)
        val wifiRatingCount = wifiReport.optJSONArray("wifi_channel_ratings")?.length() ?: 0
        val bluetoothDeviceCount = bluetoothReport.optInt("bluetooth_device_count", bluetoothReport.optJSONArray("bluetooth_devices")?.length() ?: 0)
        val bluetoothHistoryCount = bluetoothReport.optInt("bluetooth_signal_history_count", bluetoothReport.optJSONArray("bluetooth_signal_history")?.length() ?: 0)
        val bluetoothDetailCount = bluetoothReport.optInt("bluetooth_device_detail_count", bluetoothReport.optJSONArray("bluetooth_device_details")?.length() ?: 0)
        val motionQualityCount = sensorReport.optInt("motion_sensor_quality_count", sensorReport.optJSONArray("motion_sensor_quality")?.length() ?: 0)
        val motionPoseCount = sensorReport.optInt("motion_pose_estimate_count", sensorReport.optJSONArray("motion_pose_estimates")?.length() ?: 0)
        val radioCandidateCount = radioAdvisorReport.optInt("radio_receiver_candidate_count", radioAdvisorReport.optJSONArray("radio_receiver_candidates")?.length() ?: 0)
        val radioSampleCount = radioStatusReport.optInt("radio_signal_graph_sample_count", radioStatusReport.optJSONArray("radio_signal_graph_sample_rows")?.length() ?: 0)
        val acceleratorRows = acceleratorReport.optJSONArray("accelerator_preflight_matrix") ?: JSONArray()
        val mediatekRows = mediatekReport.optJSONArray("mediatek_readiness_matrix") ?: JSONArray()
        val backendAdvisorRows = backendAdvisorReport.optJSONArray("non_adreno_backend_advisor_matrix") ?: JSONArray()
        val mcpReadyCount = mcpRegistryReport.optInt("ready_mcp_tool_server_count", 0)
        val mcpTotalCount = mcpRegistryReport.optInt("mcp_tool_server_count", 0)
        return JSONArray()
            .put(agentSignalWorkflowHandoffRow(
                label = "Start with current evidence bundle",
                ready = signalEvidenceReport.optInt("signal_evidence_count", 0) > 0,
                valueLabel = "${signalEvidenceReport.optInt("signal_evidence_count", 0)} evidence row(s)",
                detail = "Signal evidence is the first passive bundle for what Hermes can currently view across Wi-Fi, Bluetooth, motion, radio boundaries, backend state, and local inference fit.",
                recommendation = "Open this before answering broad nearby-signal or Gemma-visibility questions.",
                fraction = if (signalEvidenceReport.optBoolean("success", false)) 0.96f else 0.35f,
                openNextAction = "agent_signal_evidence_report",
                graphType = "signal_evidence_matrix",
                sourceActions = listOf("agent_signal_evidence_report", "agent_signal_briefing_report", "agent_signal_timeline_report"),
                graphTypes = listOf("signal_evidence_matrix", "signal_evidence_routes", "agent_signal_briefing_matrix", "agent_signal_timeline"),
                refreshPolicy = "passive_first",
                permissionGate = "source_report_permissions",
                handoffStatus = "first_passive_evidence",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open ranked top-card planner",
                ready = priorityReport.optInt("top_signal_card_priority_count", 0) > 0,
                valueLabel = "${priorityReport.optInt("top_signal_card_priority_count", 0)} top-card row(s)",
                detail = "The top-card planner ranks the user-visible card, graph_type, open_next_action, refresh_policy, and permission_gate before Gemma explains the state.",
                recommendation = "Use this when the model must choose the expandable card to open or expand next.",
                fraction = if (priorityReport.optBoolean("success", false)) 0.95f else 0.35f,
                openNextAction = "agent_card_priority_report",
                graphType = "agent_card_priority_matrix",
                sourceActions = listOf("agent_card_priority_report", "agent_card_manifest_report", "agent_signal_evidence_report"),
                graphTypes = listOf("agent_card_priority_matrix", "agent_card_open_sequence", "agent_card_manifest"),
                refreshPolicy = "passive_card_planner",
                permissionGate = "source_report_permissions",
                handoffStatus = "top_card_route_ready",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open Wi-Fi Analyzer graph",
                ready = wifiReport.optBoolean("success", false),
                valueLabel = "$wifiGraphCount graph / $wifiRatingCount rating row(s)",
                detail = "WiFiAnalyzer-style cards expose AP/channel envelopes, channel ratings, utilization, filters, OUI/vendor hints, band coverage, and export-ready AP detail.",
                recommendation = "Open wifi_channel_graph for visual channel evidence; use refresh=true or scan_mode=resumed only when current AP rows are needed.",
                fraction = if (wifiGraphCount > 0 || wifiRatingCount > 0) 0.9f else 0.65f,
                openNextAction = "wifi_channel_graph",
                graphType = "wifi_channel_graph",
                sourceActions = listOf("wifi_analyzer_report", "wifi_channel_graph", "wifi_channel_rating", "wifi_channel_utilization", "wifi_ap_details"),
                graphTypes = listOf("wifi_channel_graph", "wifi_channel_rating", "wifi_channel_utilization", "wifi_access_point_detail"),
                refreshPolicy = "passive_by_default_refresh_when_needed",
                permissionGate = "nearby_wifi_or_location_permission",
                handoffStatus = "wifi_analyzer_card_ready",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open Bluetooth details and RSSI trends",
                ready = bluetoothReport.optBoolean("success", false),
                valueLabel = "$bluetoothDeviceCount device / $bluetoothHistoryCount history / $bluetoothDetailCount detail row(s)",
                detail = "Bluetooth rows expose paired and nearby devices, BLE RSSI history, proximity, service labels, manufacturer IDs/names, device class, details, and export metadata.",
                recommendation = "Open bluetooth_device_details for identity/service evidence or bluetooth_signal_history for proximity movement over time.",
                fraction = if (bluetoothDetailCount > 0 || bluetoothHistoryCount > 0) 0.88f else 0.62f,
                openNextAction = if (bluetoothHistoryCount > 0) "bluetooth_signal_history" else "bluetooth_device_details",
                graphType = if (bluetoothHistoryCount > 0) "bluetooth_signal_history" else "bluetooth_device_detail",
                sourceActions = listOf("bluetooth_analyzer_report", "bluetooth_signal_advisor_report", "bluetooth_signal_history", "bluetooth_device_details", "bluetooth_scan"),
                graphTypes = listOf("bluetooth_device_detail", "bluetooth_signal_history", "bluetooth_signal_advisor_matrix", "bluetooth_device_candidates"),
                refreshPolicy = "passive_after_scan_active_on_request",
                permissionGate = "bluetooth_scan_or_connect_permission",
                handoffStatus = "bluetooth_detail_route_ready",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open motion sensor quality before pose",
                ready = sensorReport.optBoolean("sensor_service_available", sensorReport.optBoolean("success", false)),
                valueLabel = "$motionQualityCount quality / $motionPoseCount pose row(s)",
                detail = "Motion quality rows keep accelerometer, gyroscope, rotation vector, linear acceleration, calibration, freshness, cadence, and workflow readiness visible before live pose sampling.",
                recommendation = "Open motion_sensor_quality first; request motion_pose sample=true only when the current orientation or motion state matters.",
                fraction = if (motionQualityCount > 0 || motionPoseCount > 0) 0.86f else 0.58f,
                openNextAction = "motion_sensor_quality",
                graphType = "motion_sensor_quality",
                sourceActions = listOf("sensor_analyzer_report", "sensor_workflow_advisor_report", "motion_sensor_quality", "motion_sensor_history", "motion_pose"),
                graphTypes = listOf("motion_sensor_quality", "motion_sensor_history", "motion_pose_estimate", "sensor_workflow_advisor_matrix"),
                refreshPolicy = "passive_metadata_live_snapshot_optional",
                permissionGate = "motion_sensor_hardware",
                handoffStatus = "motion_quality_route_ready",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open radio receiver advisor",
                ready = radioAdvisorReport.optBoolean("success", false),
                valueLabel = "$radioCandidateCount receiver candidate(s), $radioSampleCount bridge sample(s)",
                detail = "Radio advisor rows rank Android Wi-Fi/Bluetooth radio metadata, vendor AM/FM bridge requirements, external SDR routes, receiver profiles, and safe hardware-boundary messaging.",
                recommendation = "Open radio_signal_advisor_report before promising AM/FM, microwave, arbitrary RF, or SDR graph behavior.",
                fraction = if (radioCandidateCount > 0) 0.8f else 0.55f,
                openNextAction = "radio_signal_advisor_report",
                graphType = "radio_signal_advisor_matrix",
                sourceActions = listOf("radio_signal_advisor_report", "radio_signal_status", "radio_signal_graph", "sdr_bridge_samples"),
                graphTypes = listOf("radio_signal_advisor_matrix", "radio_receiver_candidates", "radio_signal_graph", "radio_receiver_bridge_schema"),
                refreshPolicy = "passive_receiver_decision_first",
                permissionGate = "vendor_radio_bridge_or_external_sdr_for_am_fm",
                bridgeRequired = radioSampleCount <= 0,
                handoffStatus = if (radioSampleCount > 0) "radio_bridge_samples_available" else "receiver_bridge_boundary_required",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open non-Adreno backend advisor",
                ready = backendAdvisorRows.length() > 0 || acceleratorRows.length() > 0 || mediatekRows.length() > 0,
                valueLabel = "${countReadyRows(backendAdvisorRows)}/${backendAdvisorRows.length()} advisor, ${countReadyRows(acceleratorRows)}/${acceleratorRows.length()} accelerator, ${countReadyRows(mediatekRows)}/${mediatekRows.length()} MediaTek row(s)",
                detail = "Backend advisor rows combine family detection, artifact lane, ABI, OpenCL visibility, backend order, LiteRT /health proof, model fit, thermal/memory runway, CPU fallback, and non-Adreno validation boundaries.",
                recommendation = "Open non_adreno_backend_advisor_report before starting local inference or making local Gemma acceleration claims.",
                fraction = if (backendAdvisorRows.length() > 0) {
                    (countReadyRows(backendAdvisorRows).toFloat() / backendAdvisorRows.length()).coerceIn(0.35f, 0.94f)
                } else if (acceleratorRows.length() > 0 || mediatekRows.length() > 0) {
                    0.78f
                } else {
                    0.35f
                },
                openNextAction = "non_adreno_backend_advisor_report",
                graphType = "non_adreno_backend_advisor_matrix",
                sourceActions = listOf("non_adreno_backend_advisor_report", "accelerator_preflight_report", "mediatek_readiness_report", "gpu_backend_risk_report", "local_backend_runtime_report"),
                graphTypes = listOf("non_adreno_backend_advisor_matrix", "accelerator_preflight_matrix", "mediatek_readiness_matrix", "gpu_backend_risk_matrix", "runtime_backend_matrix"),
                refreshPolicy = "passive_backend_launch_advisor",
                permissionGate = "phone_validation_required_for_acceleration_claims",
                physicalDeviceValidationRequired = true,
                handoffStatus = "physical_device_runtime_proof_required",
            ))
            .put(agentSignalWorkflowHandoffRow(
                label = "Open Kai/MCP registry",
                ready = mcpRegistryReport.optBoolean("success", false),
                valueLabel = "$mcpReadyCount/$mcpTotalCount MCP row(s) ready",
                detail = "MCP registry rows map Kai curated servers and tool-server expectations to native Hermes tools, simple HTTP routes, or Streamable HTTP gaps.",
                recommendation = "Open mcp_tool_server_registry_report before promising Context7, DeepWiki, Globalping, Fetch, CoinGecko, Manifold, Find-A-Domain, or custom MCP parity.",
                fraction = if (mcpTotalCount > 0) (mcpReadyCount.toFloat() / mcpTotalCount).coerceIn(0.45f, 0.9f) else 0.4f,
                openNextAction = "mcp_tool_server_registry_report",
