        val backendRiskReady = backendRiskReport.optBoolean("success", false) && backendRiskCount > 0
        val readyDomainCount = listOf(wifiReady, bluetoothReady, sensorReady, radioReady, backendRiskReady).count { it }

        return JSONArray()
