                    fraction = if (cachedMotionPoseEstimates.length() > 0) 0.9f else if (sensorNames.any { it in MOTION_HISTORY_SENSOR_TYPES }) 0.65f else 0.3f,
                    extra = JSONObject().put("tool_action", "motion_pose"),
