        frequencyMaxMhz?.let { row.put("frequency_max_mhz", it) }
        return row
    }

    private fun sampledRadioSignalGraphRows(rows: JSONArray): JSONArray {
        val sampledRows = JSONArray()
        for (index in 0 until rows.length()) {
            val row = rows.optJSONObject(index) ?: continue
            if (row.optBoolean("sampled", false)) sampledRows.put(row)
        }
        return sampledRows
    }

    private fun radioBridgeSampleMetadataRows(rows: JSONArray, arguments: JSONObject): JSONArray {
        val metadataRows = JSONArray()
        if (rows.length() == 0) {
            val observedKeys = radioObservedSampleArgumentKeys(arguments)
            metadataRows.put(
                capabilityRow(
                    category = "radio_bridge_sample_metadata",
                    label = "No radio bridge samples supplied",
                    ready = false,
                    valueLabel = if (observedKeys.isEmpty()) "schema only" else "no graphable samples",
                    detail = buildString {
                        append("Accepted arrays: radio_samples, radio_bridge_samples, sdr_samples; JSON: radio_samples_json, radio_bridge_samples_json, sdr_samples_json.")
                        if (observedKeys.isNotEmpty()) append(" Observed keys: ${observedKeys.joinToString(", ")}.")
                    },
                    recommendation = "Provide receiver-reported frequency plus RSSI/power metadata through radio_signal_graph before showing AM/FM or SDR sample rows.",
                    fraction = 0.3f,
                    extra = JSONObject()
                        .put("observed_radio_bridge_sample_argument_keys", JSONArray(observedKeys))
                        .put("accepted_radio_bridge_sample_array_keys", JSONArray(radioSampleArrayArgumentKeys()))
                        .put("accepted_radio_bridge_sample_json_keys", JSONArray(radioSampleJsonArgumentKeys()))
                        .put("accepted_radio_bridge_sample_object_keys", JSONArray(radioSampleObjectArgumentKeys())),
                ),
            )
            return metadataRows
        }
        for (index in 0 until rows.length()) {
            val row = rows.optJSONObject(index) ?: continue
            val label = row.optString("label").ifBlank { "Radio bridge sample ${index + 1}" }
            val receiverId = row.optString("receiver_id").ifBlank { "unknown_receiver" }
            val frequencyPresent = radioOptionalDouble(row, "frequency_mhz") != null ||
                radioOptionalDouble(row, "frequency_khz") != null ||
                radioOptionalDouble(row, "frequency_hz") != null ||
                radioOptionalDouble(row, "center_frequency_hz") != null
            val signalPresent = radioOptionalDouble(row, "rssi_dbm") != null ||
                radioOptionalDouble(row, "signal_dbuv_or_rssi_dbm") != null ||
                radioOptionalDouble(row, "power_db") != null
            val receiverPresent = receiverId != "unknown_receiver"
            val spanPresent = radioOptionalDouble(row, "span_hz") != null || radioOptionalDouble(row, "bandwidth_hz") != null
            val sampleRatePresent = radioOptionalDouble(row, "sample_rate_hz") != null
            val sdrSample = receiverId == "external_sdr_bridge" || row.optString("band") == "External SDR / broad RF" || row.optString("source_type") == "external_sdr"
            val requiredReady = frequencyPresent && signalPresent && receiverPresent && (!sdrSample || (spanPresent && sampleRatePresent))
            val scoreParts = listOf(frequencyPresent, signalPresent, receiverPresent, spanPresent, sampleRatePresent)
            val completenessScore = (scoreParts.count { it } * 100) / scoreParts.size
            val detail = listOfNotNull(
                row.optString("frequency_label").takeIf { it.isNotBlank() },
                row.optString("band").takeIf { it.isNotBlank() },
                "receiver=$receiverId",
                row.optString("sample_source").takeIf { it.isNotBlank() }?.let { "source=$it" },
                radioOptionalDouble(row, "rssi_dbm")?.let { "rssi=${formatDecimal(it, if (it % 1.0 == 0.0) 0 else 1)} dBm" },
                radioOptionalDouble(row, "power_db")?.let { "power=${formatDecimal(it, if (it % 1.0 == 0.0) 0 else 1)} dB" },
                radioOptionalDouble(row, "span_hz")?.let { "span_hz=${formatDecimal(it, if (it % 1.0 == 0.0) 0 else 1)}" },
                radioOptionalDouble(row, "sample_rate_hz")?.let { "sample_rate_hz=${formatDecimal(it, if (it % 1.0 == 0.0) 0 else 1)}" },
                row.optString("rds_program_service").takeIf { it.isNotBlank() }?.let { "RDS PS=$it" },
                row.optString("rds_radio_text").takeIf { it.isNotBlank() }?.let { "RDS text" },
            ).joinToString(" | ")
            metadataRows.put(
                capabilityRow(
                    category = "radio_bridge_sample_metadata",
                    label = label,
                    ready = requiredReady,
                    valueLabel = if (requiredReady) "sample ready" else "metadata incomplete",
                    detail = detail.ifBlank { "receiver=$receiverId" },
                    recommendation = if (requiredReady) {
                        "Display as bridge-provided receiver metadata; do not infer wider RF coverage beyond the reported sample span."
                    } else if (sdrSample) {
                        "External SDR samples need frequency, power/RSSI, receiver_id, span_hz, and sample_rate_hz before they are treated as spectrum-ready."
                    } else {
                        "AM/FM bridge samples need frequency, RSSI/power, and receiver_id before they are treated as station-ready."
                    },
                    fraction = completenessScore / 100f,
                    extra = JSONObject()
                        .put("sample_index", index)
                        .put("receiver_id", receiverId)
                        .put("sample_source", row.optString("sample_source"))
                        .put("frequency_metadata_present", frequencyPresent)
                        .put("signal_metadata_present", signalPresent)
                        .put("receiver_metadata_present", receiverPresent)
                        .put("span_metadata_present", spanPresent)
                        .put("sample_rate_metadata_present", sampleRatePresent)
                        .put("rds_metadata_present", row.optString("rds_program_service").isNotBlank() || row.optString("rds_radio_text").isNotBlank())
                        .put("external_sdr_sample", sdrSample)
                        .put("required_metadata_ready", requiredReady)
                        .put("metadata_completeness_score", completenessScore),
                ),
            )
        }
        return metadataRows
    }

    private fun radioObservedSampleArgumentKeys(arguments: JSONObject): List<String> {
        if (arguments.length() == 0) return emptyList()
        val acceptedKeys = (radioSampleArrayArgumentKeys() + radioSampleJsonArgumentKeys() + radioSampleObjectArgumentKeys()).toSet()
        return acceptedKeys.filter { key -> arguments.has(key) }
    }

    private fun radioSignalSampleSummaryJson(rows: JSONArray): JSONObject {
        var fmCount = 0
        var amCount = 0
        var sdrCount = 0
        var rdsCount = 0
        var strongestValue: Double? = null
        var strongestLabel = ""
        for (index in 0 until rows.length()) {
            val row = rows.optJSONObject(index) ?: continue
            when (row.optString("band")) {
                "FM broadcast" -> fmCount += 1
                "AM broadcast" -> amCount += 1
                else -> sdrCount += 1
            }
            if (row.optString("rds_program_service").isNotBlank() || row.optString("rds_radio_text").isNotBlank()) {
                rdsCount += 1
            }
            val signalValue = radioOptionalDouble(row, "rssi_dbm")
                ?: radioOptionalDouble(row, "signal_dbuv_or_rssi_dbm")
                ?: radioOptionalDouble(row, "power_db")
                ?: continue
            val previousStrongest = strongestValue
            if (previousStrongest == null || signalValue > previousStrongest) {
                strongestValue = signalValue
                strongestLabel = row.optString("label").ifBlank { row.optString("frequency_label") }
            }
        }
        return JSONObject()
            .put("sample_count", rows.length())
            .put("fm_sample_count", fmCount)
            .put("am_sample_count", amCount)
            .put("external_sdr_sample_count", sdrCount)
            .put("rds_sample_count", rdsCount)
            .put("strongest_sample_label", strongestLabel)
            .put("strongest_sample_value_db", strongestValue ?: JSONObject.NULL)
            .put("bridge_ready", rows.length() > 0)
    }

    private fun radioOptionalDouble(row: JSONObject, key: String): Double? {
        return when (val value = row.opt(key)) {
            is Number -> value.toDouble()
            is String -> value.trim().toDoubleOrNull()
            else -> null
        }
    }

    private fun radioOptionalLong(row: JSONObject, key: String): Long? {
        return when (val value = row.opt(key)) {
            is Number -> value.toLong()
            is String -> value.trim().toLongOrNull()
            else -> null
        }
    }

    private fun inferRadioSampleBand(frequencyMhz: Double?, frequencyKhz: Double?, modulation: String): String {
        val normalizedModulation = modulation.lowercase(Locale.US)
        return when {
            normalizedModulation == "am" -> "AM broadcast"
            normalizedModulation == "fm" -> "FM broadcast"
            frequencyKhz != null && frequencyKhz in 530.0..1700.0 -> "AM broadcast"
            frequencyMhz != null && frequencyMhz in 0.53..1.7 -> "AM broadcast"
            frequencyMhz != null && frequencyMhz in 87.5..108.0 -> "FM broadcast"
            else -> "External SDR / broad RF"
        }
    }

    private fun receiverIdForRadioBand(band: String): String = when (band) {
        "AM broadcast" -> "am_vendor_or_sdr"
        "FM broadcast" -> "fm_vendor_or_sdr"
        else -> "external_sdr_bridge"
    }

    private fun modulationForRadioBand(band: String): String = when (band) {
        "AM broadcast" -> "am"
        "FM broadcast" -> "fm"
        else -> "unknown"
    }

    private fun radioFrequencyLabel(frequencyMhz: Double?, frequencyKhz: Double?): String? {
        return when {
            frequencyKhz != null -> "${formatDecimal(frequencyKhz, if (frequencyKhz % 1.0 == 0.0) 0 else 1)} kHz"
            frequencyMhz != null && frequencyMhz < 2.0 -> "${formatDecimal(frequencyMhz * 1000.0, if ((frequencyMhz * 1000.0) % 1.0 == 0.0) 0 else 1)} kHz"
            frequencyMhz != null -> "${formatDecimal(frequencyMhz, if (frequencyMhz % 1.0 == 0.0) 0 else 1)} MHz"
            else -> null
        }
    }

    private fun radioSignalFraction(valueDb: Double): Double = ((valueDb + 110.0) / 80.0).coerceIn(0.08, 1.0)

    private fun radioReceiverProfileRow(
        receiverId: String,
        label: String,
        sourceType: String,
        frequencyMinKhz: Int? = null,
        frequencyMaxKhz: Int? = null,
        frequencyMinMhz: Double? = null,
        frequencyMaxMhz: Double? = null,
        channelStepLabel: String,
        publicAndroidScanSupported: Boolean,
        builtInAndroidSource: Boolean = false,
        vendorBridgePossible: Boolean = false,
        requiresVendorBridge: Boolean = false,
        requiresExternalHardware: Boolean = false,
        routeAction: String,
        accessPath: String,
        scanState: String,
        reason: String,
        recommendation: String,
        stationFields: List<String>,
        sampleFields: List<String>,
    ): JSONObject {
        val graphableMetadataSupported = publicAndroidScanSupported || vendorBridgePossible || requiresExternalHardware
        val row = JSONObject()
            .put("category", "radio_receiver_profile")
            .put("receiver_id", receiverId)
            .put("label", label)
            .put("source_type", sourceType)
            .put("ready", true)
            .put("value_label", scanState)
            .put("public_android_scan_supported", publicAndroidScanSupported)
            .put("built_in_android_source", builtInAndroidSource)
            .put("vendor_bridge_possible", vendorBridgePossible)
            .put("requires_vendor_bridge", requiresVendorBridge)
            .put("requires_external_hardware", requiresExternalHardware)
            .put("sample_rows_available", false)
            .put("graphable_metadata_supported", graphableMetadataSupported)
            .put("scan_state", scanState)
            .put("channel_step", channelStepLabel)
            .put("route_action", routeAction)
            .put("access_path", accessPath)
            .put("reason", reason)
            .put("recommendation", recommendation)
            .put("station_metadata_fields", JSONArray(stationFields))
            .put("sample_fields", JSONArray(sampleFields))
            .put("graph_row_schema", JSONArray((stationFields + sampleFields).distinct()))
            .put(
                "detail",
                "$accessPath | $channelStepLabel | ${if (publicAndroidScanSupported) "public Android metadata route" else if (vendorBridgePossible) "vendor bridge required" else if (requiresExternalHardware) "external receiver required" else "not public Android API"}",
            )
            .put(
                "fraction",
                when {
                    publicAndroidScanSupported -> 0.9f
                    vendorBridgePossible -> 0.65f
                    requiresExternalHardware -> 0.45f
                    else -> 0.3f
                },
            )
        frequencyMinKhz?.let { row.put("frequency_min_khz", it) }
        frequencyMaxKhz?.let { row.put("frequency_max_khz", it) }
        frequencyMinMhz?.let { row.put("frequency_min_mhz", it) }
        frequencyMaxMhz?.let { row.put("frequency_max_mhz", it) }
        return row
    }

