                    detail = "thermal=${performanceProfile.optString("thermal_status_label").ifBlank { "unknown" }} | memory=${performanceProfile.optString("available_memory_label").ifBlank { "unknown" }} | low_ram=$lowRam | power_saver=$powerSaveMode",
