                    detail = "soc=${socProfile.optString("soc_family").ifBlank { "unknown" }} | gpu=${socProfile.optString("gpu_family_hint").ifBlank { "unknown" }} | risk=${riskLevelForScore(maxRiskScore)} score=$maxRiskScore",
