    private fun memorySummaryJson(context: Context): JSONObject {
        val activityManager = context.getSystemService(ActivityManager::class.java)
        val info = ActivityManager.MemoryInfo()
        activityManager?.getMemoryInfo(info)
        return JSONObject()
            .put("available_bytes", info.availMem)
            .put("available_label", formatBytes(context, info.availMem))
            .put("total_bytes", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.JELLY_BEAN) info.totalMem else 0L)
            .put("total_label", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.JELLY_BEAN) formatBytes(context, info.totalMem) else "unknown")
            .put("low_memory", info.lowMemory)
            .put("threshold_bytes", info.threshold)
            .put("threshold_label", formatBytes(context, info.threshold))
            .put("app_data_free_bytes", context.filesDir.freeSpace)
            .put("app_data_total_bytes", context.filesDir.totalSpace)
            .put("app_data_free_label", formatBytes(context, context.filesDir.freeSpace))
            .put("app_data_total_label", formatBytes(context, context.filesDir.totalSpace))
    }

    private fun runningAppMemoryJson(context: Context, limit: Int): JSONArray {
        val activityManager = context.getSystemService(ActivityManager::class.java) ?: return JSONArray()
        val running = activityManager.runningAppProcesses.orEmpty()
        if (running.isEmpty()) return JSONArray()
        val memoryInfos = runCatching { activityManager.getProcessMemoryInfo(running.map { it.pid }.toIntArray()) }
            .getOrNull()
            .orEmpty()
        val rows = running.mapIndexedNotNull { index, process ->
            val pssBytes = memoryInfos.getOrNull(index)?.totalPss?.toLong()?.times(1024L) ?: return@mapIndexedNotNull null
            val packageName = process.pkgList?.firstOrNull().orEmpty().ifBlank { process.processName }
            AppResourceRow(
                packageName = packageName,
                label = appLabel(context.packageManager, packageName),
                metricBytes = pssBytes,
                extra = JSONObject()
                    .put("process_name", process.processName)
                    .put("pid", process.pid)
                    .put("importance", process.importance),
            )
        }
        return rows
            .sortedByDescending { it.metricBytes }
            .take(limit)
            .toJsonArray(context, "memory_bytes", "memory_label")
    }

    private fun topStorageAppsJson(context: Context, limit: Int): JSONArray {
        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) return JSONArray()
        val storageStatsManager = context.getSystemService(StorageStatsManager::class.java) ?: return JSONArray()
        val packageManager = context.packageManager
        val rows = mutableListOf<AppResourceRow>()
        installedApplications(packageManager).forEach { app ->
            val stats = runCatching {
                storageStatsManager.queryStatsForPackage(
                    app.storageUuid ?: StorageManager.UUID_DEFAULT,
                    app.packageName,
                    Process.myUserHandle(),
                )
            }.getOrNull() ?: return@forEach
            val total = stats.appBytes + stats.dataBytes + stats.cacheBytes
            if (total > 0L) {
                rows += AppResourceRow(
                    packageName = app.packageName,
                    label = appLabel(packageManager, app.packageName),
                    metricBytes = total,
                    extra = JSONObject()
                        .put("app_bytes", stats.appBytes)
                        .put("data_bytes", stats.dataBytes)
                        .put("cache_bytes", stats.cacheBytes)
                        .put("app_label", formatBytes(context, stats.appBytes))
                        .put("data_label", formatBytes(context, stats.dataBytes))
                        .put("cache_label", formatBytes(context, stats.cacheBytes)),
                )
            }
        }
        return rows
            .sortedByDescending { it.metricBytes }
            .take(limit)
            .toJsonArray(context, "storage_bytes", "storage_label")
    }

    private fun sampleSensors(
        sensorManager: SensorManager,
        requested: List<String>,
        targets: List<Pair<String, Sensor>>,
        timeoutMs: Long,
    ): JSONArray {
        val samples = JSONArray()
        if (targets.isEmpty()) {
            requested.forEach { key ->
                samples.put(
                    unavailableSensorJson(key),
                )
            }
            return samples
        }
        val readings = ConcurrentHashMap<Int, JSONObject>()
        val latch = CountDownLatch(targets.size)
        val listener = object : SensorEventListener {
            override fun onSensorChanged(event: SensorEvent) {
                if (readings.containsKey(event.sensor.type)) return
                val values = JSONArray()
                event.values.forEach { values.put(it.toDouble()) }
                val sensorType = canonicalSensorType(event.sensor)
                readings[event.sensor.type] = sensorMetadataJson(sensorType, event.sensor)
                    .put("sampled", true)
                    .put("values", values)
                    .put("timestamp_nanos", event.timestamp)
                    .put("accuracy", event.accuracy)
                    .put("accuracy_label", sensorAccuracyLabel(event.accuracy))
                latch.countDown()
            }

            override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) = Unit
        }
        val thread = HandlerThread("HermesSensorSnapshot")
        thread.start()
        val handler = Handler(thread.looper)
        try {
            targets.forEach { (_, sensor) ->
                sensorManager.registerListener(listener, sensor, SensorManager.SENSOR_DELAY_NORMAL, handler)
            }
            latch.await(timeoutMs, TimeUnit.MILLISECONDS)
        } finally {
            sensorManager.unregisterListener(listener)
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.JELLY_BEAN_MR2) {
                thread.quitSafely()
            } else {
                thread.quit()
            }
        }
        targets.forEach { (key, sensor) ->
            samples.put(
                readings[sensor.type] ?: JSONObject()
                    .put("sensor_label", SENSOR_TYPE_LABELS[key] ?: key)
                    .put("sensor_type", key)
                    .put("sensor_name", sensor.name.orEmpty())
                    .put("vendor", sensor.vendor.orEmpty())
                    .put("unit", unitForSensorType(key))
                    .put("available", true)
                    .put("sampled", false),
            )
        }
        val sampledKeys = targets.map { it.first }.toSet()
        requested.filterNot { it in sampledKeys }.forEach { key ->
            samples.put(
                unavailableSensorJson(key),
            )
        }
        return samples
    }

    private fun sensorCapabilityRows(sensorManager: SensorManager, requested: List<String>): JSONArray {
        val rows = JSONArray()
        requested.forEach { key ->
            val sensor = androidSensorType(key)?.let { sensorManager.getDefaultSensor(it) }
            rows.put(
                if (sensor != null) {
                    sensorMetadataJson(key, sensor)
                } else {
                    unavailableSensorJson(key)
                },
            )
        }
        return rows
    }

    private fun unavailableSensorRows(requested: List<String>): JSONArray {
        val rows = JSONArray()
        requested.forEach { key -> rows.put(unavailableSensorJson(key)) }
        return rows
    }

    private fun sensorMetadataJson(sensorType: String, sensor: Sensor): JSONObject {
        return JSONObject()
            .put("sensor_type", sensorType)
            .put("sensor_label", SENSOR_TYPE_LABELS[sensorType] ?: sensorType)
            .put("sensor_name", sensor.name.orEmpty())
            .put("vendor", sensor.vendor.orEmpty())
            .put("version", sensor.version)
            .put("unit", unitForSensorType(sensorType))
            .put("available", true)
            .put("sampled", false)
            .put("maximum_range", sensor.maximumRange.toDouble())
            .put("resolution", sensor.resolution.toDouble())
            .put("power_ma", sensor.power.toDouble())
            .put("min_delay_us", sensor.minDelay)
            .put("max_delay_us", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) sensor.maxDelay else 0)
            .put("fifo_reserved_event_count", sensor.fifoReservedEventCount)
            .put("fifo_max_event_count", sensor.fifoMaxEventCount)
            .put("reporting_mode", sensorReportingModeLabel(sensor))
            .put("wake_up", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) sensor.isWakeUpSensor else false)
            .put("dynamic_sensor", if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) sensor.isDynamicSensor else false)
            .put("direct_channel_supported", sensorDirectChannelSupported(sensor))
            .put("highest_direct_report_rate_level", sensorHighestDirectReportRate(sensor))
    }

    private fun unavailableSensorJson(sensorType: String): JSONObject {
        return JSONObject()
            .put("sensor_type", sensorType)
            .put("sensor_label", SENSOR_TYPE_LABELS[sensorType] ?: sensorType)
            .put("unit", unitForSensorType(sensorType))
            .put("available", false)
            .put("sampled", false)
    }

    private fun countSensorCapabilities(rows: JSONArray, sensorTypes: Set<String>): Int {
        var count = 0
        for (index in 0 until rows.length()) {
            val row = rows.optJSONObject(index) ?: continue
            if (row.optBoolean("available", false) && row.optString("sensor_type") in sensorTypes) {
                count += 1
            }
        }
        return count
    }

    private fun countSensorCapabilityFlag(rows: JSONArray, flag: String): Int {
        var count = 0
        for (index in 0 until rows.length()) {
            val row = rows.optJSONObject(index) ?: continue
            if (row.optBoolean(flag, false)) {
                count += 1
            }
        }
        return count
    }

    private fun wifiConnectionStatusJson(
        context: Context,
        wifiManager: WifiManager?,
        permissionStatus: JSONObject,
        scanNetworks: JSONArray,
    ): JSONObject {
        val info = runCatching { wifiManager?.connectionInfo }.getOrNull()
        val wifiEnabled = wifiManager?.isWifiEnabled == true
        val ssid = normalizeConnectedWifiSsid(info?.ssid.orEmpty())
        val rawBssid = info?.bssid.orEmpty()
        val bssid = rawBssid.takeUnless { wifiBssidIsRedactedOrUnknown(it) }.orEmpty()
        val rssiDbm = (info?.rssi ?: Int.MIN_VALUE).takeIf { it in -127..0 }
        val frequencyMhz = (info?.frequency ?: 0).takeIf { it > 0 }
        val linkSpeedMbps = (info?.linkSpeed ?: -1).takeIf { it > 0 }
        val txLinkSpeedMbps = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            runCatching { info?.txLinkSpeedMbps?.takeIf { it > 0 } }.getOrNull()
        } else {
            null
        }
        val rxLinkSpeedMbps = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
            runCatching { info?.rxLinkSpeedMbps?.takeIf { it > 0 } }.getOrNull()
        } else {
            null
        }
        val wifiStandard = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            runCatching { info?.wifiStandard?.let(::wifiStandardLabel) }.getOrNull().orEmpty()
        } else {
            ""
        }
        val securityType = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            runCatching { info?.currentSecurityType?.let(::wifiSecurityTypeLabel) }.getOrNull().orEmpty()
        } else {
            ""
        }
        val networkId = info?.networkId ?: -1
        val channel = frequencyMhz?.let(::channelForFrequencyMhz)
        val band = frequencyMhz?.let(::wifiBandLabel).orEmpty()
        val matchedScanRow = findWifiConnectionScanRow(scanNetworks, ssid, bssid)
        val connected = wifiEnabled && (networkId != -1 || ssid.isNotBlank() || bssid.isNotBlank() || frequencyMhz != null)
        val locationEnabled = context.getSystemService(LocationManager::class.java)
            ?.let { manager ->
                runCatching {
                    manager.isProviderEnabled(LocationManager.GPS_PROVIDER) || manager.isProviderEnabled(LocationManager.NETWORK_PROVIDER)
                }.getOrDefault(false)
            }
            ?: false
        return JSONObject()
            .put("wifi_enabled", wifiEnabled)
            .put("connected", connected)
            .put("ssid", ssid.takeIf { it.isNotBlank() } ?: JSONObject.NULL)
            .put("raw_ssid_redacted_or_unknown", ssid.isBlank() && info?.ssid.orEmpty().isNotBlank())
            .put("bssid", bssid.takeIf { it.isNotBlank() } ?: JSONObject.NULL)
            .put("bssid_redacted_or_unknown", rawBssid.isNotBlank() && bssid.isBlank())
            .put("network_id", if (networkId >= 0) networkId else JSONObject.NULL)
            .put("rssi_dbm", rssiDbm ?: JSONObject.NULL)
            .put("signal_quality", rssiDbm?.let(::wifiSignalQualityLabel) ?: "unknown")
            .put("link_speed_mbps", linkSpeedMbps ?: JSONObject.NULL)
            .put("tx_link_speed_mbps", txLinkSpeedMbps ?: JSONObject.NULL)
            .put("rx_link_speed_mbps", rxLinkSpeedMbps ?: JSONObject.NULL)
            .put("frequency_mhz", frequencyMhz ?: JSONObject.NULL)
            .put("channel", channel ?: JSONObject.NULL)
            .put("band", band.ifBlank { "unknown" })
            .put("wifi_standard", wifiStandard.ifBlank { matchedScanRow?.optString("wifi_standard").orEmpty().ifBlank { "unknown" } })
            .put("security_type", securityType.ifBlank { matchedScanRow?.optString("security_mode").orEmpty().ifBlank { "unknown" } })
            .put("matched_scan_row_available", matchedScanRow != null)
            .put("matched_bssid_vendor", matchedScanRow?.optString("bssid_vendor").orEmpty().takeIf { it.isNotBlank() } ?: JSONObject.NULL)
            .put("matched_channel_width", matchedScanRow?.optString("channel_width").orEmpty().takeIf { it.isNotBlank() } ?: JSONObject.NULL)
            .put("matched_channel_width_mhz", matchedScanRow?.let { jsonIntOrNull(it, "channel_width_mhz") } ?: JSONObject.NULL)
            .put("matched_security_mode", matchedScanRow?.optString("security_mode").orEmpty().takeIf { it.isNotBlank() } ?: JSONObject.NULL)
            .put("matched_scan_row", matchedScanRow?.let { JSONObject(it.toString()) } ?: JSONObject.NULL)
            .put("can_read_scan_results", permissionStatus.optBoolean("can_read_scan_results", false))
            .put("location_enabled", locationEnabled)
            .put("privacy_note", "SSID/BSSID and link metadata may be redacted by Android unless nearby Wi-Fi/location permission and location services are available.")
    }

    private fun wifiConnectionLinkRows(connectionStatus: JSONObject, accessPointDetails: JSONArray): JSONArray {
        val connected = connectionStatus.optBoolean("connected", false)
        val wifiEnabled = connectionStatus.optBoolean("wifi_enabled", false)
        val ssid = connectionStatus.optString("ssid")
        val bssid = connectionStatus.optString("bssid")
        val rssiDbm = jsonIntOrNull(connectionStatus, "rssi_dbm")
        val linkSpeedMbps = jsonIntOrNull(connectionStatus, "link_speed_mbps")
        val txLinkSpeedMbps = jsonIntOrNull(connectionStatus, "tx_link_speed_mbps")
        val rxLinkSpeedMbps = jsonIntOrNull(connectionStatus, "rx_link_speed_mbps")
        val frequencyMhz = jsonIntOrNull(connectionStatus, "frequency_mhz")
        val channel = jsonIntOrNull(connectionStatus, "channel")
        val band = connectionStatus.optString("band").ifBlank { "unknown" }
        val standard = connectionStatus.optString("wifi_standard").ifBlank { "unknown" }
        val security = connectionStatus.optString("security_type").ifBlank { "unknown" }
        val matched = connectionStatus.optBoolean("matched_scan_row_available", false)
        val matchedDetail = findWifiConnectionScanRow(accessPointDetails, ssid, bssid)
        return JSONArray()
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Current Wi-Fi association",
                    ready = connected,
                    valueLabel = if (connected) ssid.ifBlank { "connected, SSID redacted" } else if (wifiEnabled) "not associated" else "Wi-Fi disabled",
                    detail = "ssid=${ssid.ifBlank { "redacted_or_unknown" }} | bssid=${bssid.ifBlank { "redacted_or_unknown" }} | network_id=${connectionStatus.opt("network_id")}",
                    recommendation = "Use this row before explaining the user's active Wi-Fi path; ask for Wi-Fi/location permission only when Android redacts association details.",
                    fraction = if (connected) 0.95f else if (wifiEnabled) 0.45f else 0.15f,
                    extra = JSONObject()
                        .put("tool_action", "wifi_connection_link")
                        .put("graph_type", "wifi_connection_link"),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Link RSSI quality",
                    ready = connected && rssiDbm != null,
                    valueLabel = rssiDbm?.let { "$it dBm ${wifiSignalQualityLabel(it)}" } ?: "RSSI unavailable",
                    detail = "Android connection RSSI=${rssiDbm ?: "unknown"} dBm; scan_match=$matched; signal_quality=${connectionStatus.optString("signal_quality").ifBlank { "unknown" }}.",
                    recommendation = "Combine current RSSI with Wi-Fi signal history before diagnosing roaming, weak rooms, or unstable connectivity.",
                    fraction = rssiDbm?.let(::wifiSignalFraction) ?: if (connected) 0.5f else 0.2f,
                    extra = JSONObject()
                        .put("tool_action", "wifi_signal_history")
                        .put("source_surface", "WifiInfo.rssi"),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Link speed telemetry",
                    ready = connected && (linkSpeedMbps != null || txLinkSpeedMbps != null || rxLinkSpeedMbps != null),
                    valueLabel = linkSpeedMbps?.let { "$it Mbps" } ?: "speed unavailable",
                    detail = "link=${linkSpeedMbps ?: "unknown"} Mbps | tx=${txLinkSpeedMbps ?: "unknown"} Mbps | rx=${rxLinkSpeedMbps ?: "unknown"} Mbps",
                    recommendation = "Use link speed as a connection hint, not a throughput guarantee; combine it with channel width, RSSI, and band rows.",
                    fraction = wifiLinkSpeedFraction(linkSpeedMbps, txLinkSpeedMbps, rxLinkSpeedMbps),
                    extra = JSONObject()
                        .put("tool_action", "wifi_connection_link")
                        .put("source_surface", "WifiInfo.linkSpeed"),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Connected channel and band",
                    ready = connected && frequencyMhz != null,
                    valueLabel = listOfNotNull(band.takeIf { it != "unknown" }, channel?.let { "ch $it" }).joinToString(" ").ifBlank { "frequency unavailable" },
                    detail = "frequency=${frequencyMhz ?: "unknown"} MHz | channel=${channel ?: "unknown"} | matched_width=${connectionStatus.opt("matched_channel_width")}",
                    recommendation = "Use this with Wi-Fi channel graph and utilization cards when explaining whether the current AP sits on a crowded or wide channel.",
                    fraction = if (frequencyMhz != null && channel != null) 0.95f else if (connected) 0.55f else 0.2f,
                    extra = JSONObject()
                        .put("tool_action", "wifi_channel_graph")
                        .put("graph_type", "wifi_channel_graph"),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Standard and security context",
                    ready = connected && (standard != "unknown" || security != "unknown"),
                    valueLabel = listOf(standard, security).filter { it != "unknown" }.joinToString(" / ").ifBlank { "metadata unavailable" },
                    detail = "wifi_standard=$standard | security=$security | matched_security=${connectionStatus.opt("matched_security_mode")}",
                    recommendation = "Use this row to avoid inferring modern throughput or security posture from band/RSSI alone.",
                    fraction = if (standard != "unknown" && security != "unknown") 0.9f else if (standard != "unknown" || security != "unknown") 0.72f else 0.35f,
                    extra = JSONObject()
                        .put("tool_action", "wifi_connection_link")
                        .put("source_surface", "WifiInfo and scan metadata"),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_connection_link",
                    label = "Current AP scan match",
                    ready = matched || matchedDetail != null,
                    valueLabel = if (matched || matchedDetail != null) "scan row matched" else "connection-only metadata",
                    detail = listOf(
                        "vendor=${connectionStatus.optString("matched_bssid_vendor").ifBlank { matchedDetail?.optString("bssid_vendor").orEmpty().ifBlank { "unknown" } }}",
                        "width=${connectionStatus.optString("matched_channel_width").ifBlank { matchedDetail?.optString("channel_width").orEmpty().ifBlank { "unknown" } }}",
                        "security_attention=${matchedDetail?.optString("security_attention").orEmpty().ifBlank { "unknown" }}",
                    ).joinToString(" | "),
                    recommendation = "When matched, combine active-link metadata with AP semantic rows; when not matched, explain Android permission redaction or scan age.",
                    fraction = if (matched || matchedDetail != null) 0.92f else if (connected) 0.48f else 0.2f,
                    extra = JSONObject()
                        .put("tool_action", "wifi_ap_details")
                        .put("graph_type", "wifi_access_point_detail"),
                ),
            )
    }

    internal fun wifiSignalAdvisorRows(analyzerReport: JSONObject, coexistenceReport: JSONObject): JSONArray {
        val permissionStatus = analyzerReport.optJSONObject("wifi_scan_permission_status") ?: JSONObject()
        val connectionStatus = analyzerReport.optJSONObject("wifi_connection_status") ?: JSONObject()
        val connectionRows = analyzerReport.optJSONArray("wifi_connection_link") ?: JSONArray()
        val recommendedChannels = analyzerReport.optJSONArray("recommended_wifi_channels") ?: JSONArray()
        val utilizationRows = analyzerReport.optJSONArray("wifi_channel_utilization") ?: JSONArray()
        val roamingRows = wifiRoamingCandidateRows(analyzerReport)
        val coexistenceRows = coexistenceReport.optJSONArray("rf_coexistence_matrix") ?: JSONArray()
        val bestChannel = bestWifiRecommendationRow(recommendedChannels)
        val busiestChannel = busiestWifiUtilizationRow(utilizationRows)
        val bestRoaming = roamingRows.optJSONObject(0)
        val connected = connectionStatus.optBoolean("connected", false)
        val wifiEnabled = connectionStatus.optBoolean("wifi_enabled", false)
        val ssid = jsonCleanString(connectionStatus, "ssid")
        val rssiDbm = jsonIntOrNull(connectionStatus, "rssi_dbm")
        val band = connectionStatus.optString("band").ifBlank { "unknown" }
        val channel = jsonIntOrNull(connectionStatus, "channel")
        val permissionReady = permissionStatus.optBoolean("can_read_scan_results", false)
        val rfRiskLevel = coexistenceReport.optString("rf_coexistence_risk_level").ifBlank { "unknown" }
        val rfRiskScore = coexistenceReport.optInt("rf_coexistence_risk_score", 0).coerceIn(0, 100)
        return JSONArray()
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "Current link decision",
                    ready = connected,
                    valueLabel = when {
                        connected && rssiDbm != null -> "${rssiDbm} dBm ${wifiSignalQualityLabel(rssiDbm)}"
                        connected -> ssid.ifBlank { "connected" }
                        wifiEnabled -> "not associated"
                        else -> "Wi-Fi disabled"
                    },
                    detail = "ssid=${ssid.ifBlank { "redacted_or_unknown" }} | band=$band | channel=${channel ?: "unknown"} | ready_link_rows=${countReadyRows(connectionRows)}",
                    recommendation = "Start with this row before advising on roaming or channel changes; weak RSSI and current channel context decide whether to inspect AP candidates or channel ratings next.",
                    fraction = rssiDbm?.let(::wifiSignalFraction) ?: if (connected) 0.72f else if (wifiEnabled) 0.35f else 0.12f,
                    extra = JSONObject()
                        .put("source_action", "wifi_connection_link")
                        .put("tool_action", "wifi_connection_link")
                        .put("open_next_action", "wifi_connection_link")
                        .put("graph_type", "wifi_connection_link")
                        .put("metadata_keys", jsonStringArray(listOf("wifi_connection_status", "wifi_connection_link", "wifi_signal_history"))),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "Best channel recommendation",
                    ready = bestChannel != null,
                    valueLabel = bestChannel?.let { "${it.optString("band")} ch ${it.optInt("channel")} ${it.optString("rating_label").ifBlank { "rated" }}" }
                        ?: "scan data unavailable",
                    detail = bestChannel?.let {
                        "score=${it.optInt("score")} | ${it.optString("recommendation").ifBlank { "Channel rating row available." }}"
                    } ?: "No recommended channel rows are available until Android exposes scan results.",
                    recommendation = "Use this row for router channel questions, then cross-check utilization before recommending a change.",
                    fraction = bestChannel?.optInt("score")?.div(100f) ?: 0.32f,
                    extra = JSONObject()
                        .put("source_action", "wifi_channel_rating")
                        .put("tool_action", "wifi_channel_rating")
                        .put("open_next_action", "wifi_channel_rating")
                        .put("graph_type", "wifi_channel_rating")
                        .put("metadata_keys", jsonStringArray(listOf("recommended_wifi_channels", "wifi_channel_ratings"))),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "Congestion and overlap decision",
                    ready = busiestChannel != null,
                    valueLabel = busiestChannel?.let { "${it.optString("band")} ch ${it.optInt("channel")} ${it.optString("utilization_label").ifBlank { "observed" }}" }
                        ?: "occupancy unavailable",
                    detail = busiestChannel?.let {
                        "pressure=${it.optInt("channel_pressure_score")} | overlap=${it.optInt("overlap_count")} | strongest=${jsonIntOrNull(it, "strongest_rssi_dbm") ?: "unknown"} dBm"
                    } ?: "No channel utilization rows are available until Android exposes scan results.",
                    recommendation = "Use this row when the user asks about interference or crowded airspace; prefer higher-rated channels only if utilization also looks acceptable.",
                    fraction = busiestChannel?.optInt("channel_pressure_score")?.let { (100 - it).coerceIn(5, 100) / 100f } ?: 0.3f,
                    extra = JSONObject()
                        .put("source_action", "wifi_channel_utilization")
                        .put("tool_action", "wifi_channel_utilization")
                        .put("open_next_action", "wifi_channel_utilization")
                        .put("graph_type", "wifi_channel_utilization")
                        .put("metadata_keys", jsonStringArray(listOf("wifi_channel_utilization", "wifi_channel_graph"))),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "Roaming candidate decision",
                    ready = bestRoaming != null,
                    valueLabel = bestRoaming?.optString("value_label").orEmpty().ifBlank { "no candidate AP rows" },
                    detail = bestRoaming?.let {
                        "${it.optString("label")} | score=${it.optInt("roaming_score")} | same_ssid=${it.optBoolean("same_ssid", false)} | current_ap=${it.optBoolean("current_bssid", false)}"
                    } ?: "No visible AP rows can be ranked for roaming until scan metadata is available.",
                    recommendation = "Use this row for room-to-room movement, mesh, or multiple-AP troubleshooting; treat rows as signal evidence rather than network access capability.",
                    fraction = bestRoaming?.optInt("roaming_score")?.div(100f) ?: 0.28f,
                    extra = JSONObject()
                        .put("source_action", "wifi_ap_details")
                        .put("tool_action", "wifi_ap_details")
                        .put("open_next_action", "wifi_connection_link")
                        .put("graph_type", "wifi_roaming_candidates")
                        .put("metadata_keys", jsonStringArray(listOf("wifi_roaming_candidates", "wifi_access_point_details", "wifi_connection_status"))),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "Permission and refresh decision",
                    ready = permissionReady,
                    valueLabel = wifiAdvisorPermissionLabel(permissionStatus),
                    detail = "fine_location=${permissionStatus.optBoolean("fine_location_granted", false)} | nearby_wifi=${permissionStatus.optBoolean("nearby_wifi_devices_granted", false)} | location_enabled=${permissionStatus.optBoolean("location_enabled", false)}",
                    recommendation = "Use this row before requesting repeated scans; explain permission gates and Android scan throttling instead of pretending live rows exist.",
                    fraction = if (permissionReady) 0.95f else 0.38f,
                    extra = JSONObject()
                        .put("source_action", "wifi_analyzer_report")
                        .put("tool_action", "wifi_analyzer_report")
                        .put("open_next_action", "wifi_analyzer_report")
                        .put("graph_type", "wifi_scan_policy_matrix")
                        .put("permission_gate", "fine location, nearby Wi-Fi, location services")
                        .put("metadata_keys", jsonStringArray(listOf("wifi_scan_permission_status", "wifi_scan_status", "wifi_scan_policy_matrix"))),
                ),
            )
            .put(
                capabilityRow(
                    category = "wifi_signal_advisor",
                    label = "2.4 GHz coexistence decision",
                    ready = coexistenceRows.length() > 0,
                    valueLabel = if (coexistenceRows.length() > 0) "$rfRiskLevel risk" else "coexistence unavailable",
                    detail = "rf_coexistence_rows=${coexistenceRows.length()} | risk_score=$rfRiskScore | risk_level=$rfRiskLevel",
                    recommendation = "Use this row when 2.4GHz Wi-Fi, Bluetooth, or external radio context may explain instability before changing router or backend settings.",
                    fraction = if (coexistenceRows.length() > 0) (100 - rfRiskScore).coerceIn(15, 100) / 100f else 0.32f,
                    extra = JSONObject()
                        .put("source_action", "rf_coexistence_report")
                        .put("tool_action", "rf_coexistence_report")
                        .put("open_next_action", "rf_coexistence_report")
                        .put("graph_type", "rf_coexistence_matrix")
                        .put("metadata_keys", jsonStringArray(listOf("rf_coexistence_matrix", "wifi_channel_utilization", "bluetooth_metadata_summary"))),
                ),
            )
    }

